    45→// ═══════════════════════════════════════════════════════════════
    46→// WEBSOCKET BRIDGE — connects Claude Code ↔ ClawCraft UI
    47→// Port 9477, JSON protocol
    48→// ═══════════════════════════════════════════════════════════════
    49→function startBridge() {
    50→  wss = new WebSocketServer({ port: BRIDGE_PORT });
    51→  console.log(`[Bridge] WebSocket server listening on ws://localhost:${BRIDGE_PORT}`);
    52→
    53→  wss.on('connection', (ws) => {
    54→    console.log('[Bridge] Client connected');
    55→    ws.send(JSON.stringify({ type: 'connected', message: 'ClawCraft bridge ready' }));
    56→
    57→    // Forward orchestrator events to bridge clients
    58→    const forwardEvent = (event) => {
    59→      if (ws.readyState === 1) {
    60→        ws.send(JSON.stringify({ type: 'event', event }));
    61→      }
    62→    };
    63→    orchestrator.on('event', forwardEvent);
    64→
    65→    ws.on('message', async (raw) => {
    66→      let msg;
    67→      try { msg = JSON.parse(raw); } catch { ws.send(JSON.stringify({ type: 'error', error: 'invalid JSON' })); return; }
    68→
    69→      try {
    70→        registerBridgeSession(msg.client);
    71→        let result;
    72→        switch (msg.action) {
    73→          case 'hello':
    74→            result = registerBridgeSession(msg.client || msg.payload || {});
    75→            break;
    76→          case 'getState':
    77→            result = orchestrator.getState();
    78→            break;
    79→          case 'createAgent':
    80→            result = orchestrator.createAgent(msg.payload || {});
    81→            break;
    82→          case 'removeAgent':
    83→            result = await orchestrator.removeAgent(msg.agentId);
    84→            break;
    85→          case 'startRun':
    86→            result = await orchestrator.startRun(msg.payload || {});
    87→            break;
    88→          case 'cancelRun':
    89→            result = await orchestrator.cancelRun(msg.runId);
    90→            break;
    91→          case 'startRelay':
    92→            result = await orchestrator.startRelay(msg.payload || {});
    93→            break;
    94→          case 'getDiff':
    95→            result = orchestrator.getAgentDiff(msg.agentId);
    96→            break;
    97→          case 'listAgents':
    98→            result = orchestrator.listAgents();
    99→            break;
   100→          default:
   101→            result = { error: `Unknown action: ${msg.action}` };
   102→        }
   103→        ws.send(JSON.stringify({ type: 'response', id: msg.id, result }));
   104→      } catch (err) {
   105→        ws.send(JSON.stringify({ type: 'error', id: msg.id, error: err.message }));
   106→      }
   107→    });
   108→
   109→    ws.on('close', () => {
   110→      console.log('[Bridge] Client disconnected');
   111→      orchestrator.removeListener('event', forwardEvent);
   112→    });
   113→  });
   114→}
   115→
   116→app.whenReady().then(() => {
   117→  orchestrator = new AgentOrchestrator(path.resolve(__dirname, '..'));
   118→  orchestrator.on('event', (payload) => {
   119→    if (mainWindow && !mainWindow.isDestroyed()) {
   120→      mainWindow.webContents.send('orchestrator:event', payload);
   121→    }
   122→  });
   123→  registerIpcHandlers();
   124→  startBridge();
   125→  createWindow();
   126→});
   127→
   128→app.on('window-all-closed', () => {
   129→  if (process.platform !== 'darwin') app.quit();
   130→});
   131→
   132→app.on('activate', () => {
   133→  if (BrowserWindow.getAllWindows().length === 0) createWindow();
   134→});
   135→
   136→app.on('before-quit', async (e) => {
   137→  if (orchestrator) {
   138→    e.preventDefault();
   139→    if (wss) wss.close();
   140→    await orchestrator.shutdown();
   141→    app.exit(0);
   142→  }
   143→});
   144→"}]},"parent_tool_use_id":"toolu_01DA9FVKLnarb8mZ4P6fupmm","session_id":"882ced72-4f4c-48a8-94aa-c54bd6e7bd3a","uuid":"d650290b-3cba-469d-a8b0-955dfd9fb76f"}

{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_01MfeoMqdBU9nr4H2WCXBWSe","type":"tool_result","content":"     1→#!/usr/bin/env node
     2→// ClawCraft Bridge CLI — send commands to running Electron app via WebSocket
     3→// Usage: node bridge.js <action> [JSON args]
     4→// Examples:
     5→//   node bridge.js getState
     6→//   node bridge.js createAgent '{"engine":"claude","name":"Claude-01"}'
     7→//   node bridge.js startRun '{"agentId":"1","prompt":"Fix the bug in app.js"}'
     8→//   node bridge.js listAgents
     9→//   node bridge.js getDiff 1
    10→//   node bridge.js removeAgent 1
    11→
    12→const WebSocket = require('ws');
    13→const BRIDGE_URL = 'ws://localhost:9477';
    14→
    15→function sanitizeToken(value) {
    16→  return String(value || '')
    17→    .trim()
    18→    .toLowerCase()
    19→    .replace(/[^a-z0-9._-]+/g, '-')
    20→    .replace(/^-+|-+$/g, '') || 'session';
    21→}
    22→
    23→function buildClientMeta() {
    24→  const threadId = process.env.CODEX_THREAD_ID || '';
    25→  const termSessionId = process.env.TERM_SESSION_ID || '';
    26→  const token = threadId || termSessionId || `pid-${process.pid}`;
    27→  const shortToken = String(token).slice(0, 8);
    28→  return {
    29→    sessionId: `codex-cli-${sanitizeToken(token)}`,
    30→    threadId,
    31→    termSessionId,
    32→    pid: process.pid,
    33→    name: 'Codex CLI',
    34→    engine: 'codex',
    35→    model: 'gpt-5',
    36→    role: 'assistant',
    37→    locked: true,
    38→    sessionKind: 'codex-cli',
    39→    taskTitle: `Talking with you in CLI ${shortToken}`,
    40→  };
    41→}
    42→
    43→const action = process.argv[2];
    44→if (!action) {
    45→  console.log('Usage: node bridge.js <action> [args]');
    46→  console.log('Actions: getState, listAgents, createAgent, removeAgent, startRun, cancelRun, startRelay, getDiff');
    47→  process.exit(1);
    48→}
    49→
    50→const arg = process.argv[3];
    51→let payload, agentId, runId;
    52→
    53→try {
    54→  if (action === 'removeAgent' || action === 'getDiff') {
    55→    agentId = arg;
    56→  } else if (action === 'cancelRun') {
    57→    runId = arg;
    58→  } else if (arg) {
    59→    payload = JSON.parse(arg);
    60→  }
    61→} catch {
    62→  payload = { prompt: arg };
    63→}
    64→
    65→const ws = new WebSocket(BRIDGE_URL);
    66→const msgId = Date.now().toString();
    67→const client = buildClientMeta();
    68→
    69→ws.on('open', () => {
    70→  const msg = { id: msgId, action };
    71→  msg.client = client;
    72→  if (payload) msg.payload = payload;
    73→  if (agentId) msg.agentId = agentId;
    74→  if (runId) msg.runId = runId;
    75→  ws.send(JSON.stringify(msg));
    76→});
    77→
    78→ws.on('message', (raw) => {
    79→  const data = JSON.parse(raw);
    80→  if (data.type === 'connected') return;
    81→  if (data.type === 'response' && data.id === msgId) {
    82→    console.log(JSON.stringify(data.result, null, 2));
    83→    ws.close();
    84→  }
    85→  if (data.type === 'error' && data.id === msgId) {
    86→    console.error('Error:', data.error);
    87→    ws.close();
    88→    process.exit(1);
    89→  }
    90→  if (data.type === 'event') {
    91→    // Stream events if waiting
    92→    const e = data.event;
    93→    if (e.type === 'run.phase') process.stderr.write(`[${e.phase}] ${e.label || ''} ${Math.round((e.progress||0)*100)}%\n`);
    94→    if (e.type === 'run.output') process.stderr.write(`[output] ${e.text?.slice(0,200)}\n`);
    95→    if (e.type === 'run.completed') { console.log('\n✅ Run completed'); ws.close(); }
    96→    if (e.type === 'run.failed') { console.error('\n❌ Run failed:', e.errorText); ws.close(); process.exit(1); }
    97→  }
    98→});
    99→
   100→ws.on('error', (err) => {
   101→  console.error('Connection failed. Is ClawCraft Electron app running? (npm start)');
   102→  console.error(err.message);
   103→  process.exit(1);
   104→});
   105→
   106→// Timeout
   107→setTimeout(() => { console.error('Timeout'); ws.close(); process.exit(1); }, 30000);
   108→"}]},"parent_tool_use_id":"toolu_01DA9FVKLnarb8mZ4P6fupmm","session_id":"882ced72-4f4c-48a8-94aa-c54bd6e7bd3a","uuid":"7a2bab65-3f9c-4797-9b6c-1e5d2b24a6f5"}

{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_01AEsPPEA469kNyeHUJCXvXe","type":"tool_result","content":"     1→const { EventEmitter } = require('events');
     2→const { spawn } = require('child_process');
     3→const path = require('path');
     4→const readline = require('readline');
     5→
     6→const { RunStore } = require('./run-store');
     7→const { WorkspaceManager } = require('./workspace-manager');
     8→const { AgentRegistry } = require('./agent-registry');
     9→const { MessageBus } = require('./message-bus');
    10→const { PromptCompiler } = require('./prompt-compiler');
    11→const { CodexAdapter } = require('../engines/codex-adapter');
    12→const { ClaudeAdapter } = require('../engines/claude-adapter');
    13→const { GeminiAdapter } = require('../engines/gemini-adapter');
    14→
    15→const PHASE_LIMITS = {
    16→  queued: 0.04,
    17→  planning: 0.18,
    18→  coding: 0.82,
    19→  testing: 0.92,
    20→  summarizing: 0.97,
    21→  done: 1,
    22→};
    23→
    24→function sanitizeSessionToken(value) {
    25→  return String(value || '')
    26→    .trim()
    27→    .toLowerCase()
    28→    .replace(/[^a-z0-9._-]+/g, '-')
    29→    .replace(/^-+|-+$/g, '') || 'session';
    30→}
    31→
    32→function buildSessionAgent(payload = {}) {
    33→  const token = payload.threadId || payload.termSessionId || payload.sessionId || payload.id || 'session';
    34→  const shortToken = String(token).slice(0, 8);
    35→  const sessionId = payload.sessionId || payload.id || `codex-cli-${sanitizeSessionToken(token)}`;
    36→  return {
    37→    id: sessionId,
    38→    name: payload.name || 'Codex CLI',
    39→    engine: payload.engine || 'codex',
    40→    model: payload.model || 'gpt-5',
    41→    role: payload.role || 'assistant',
    42→    locked: payload.locked !== false,
    43→    sessionKind: payload.sessionKind || 'codex-cli',
    44→    taskTitle: payload.taskTitle || `Talking with you in CLI ${shortToken}`,
    45→  };
    46→}
    47→
    48→function buildPrimarySessionAgent(env = process.env) {
    49→  const threadId = env.CODEX_THREAD_ID || '';
    50→  const termSessionId = env.TERM_SESSION_ID || '';
    51→  if (!threadId && !termSessionId) return null;
    52→  return buildSessionAgent({
    53→    threadId,
    54→    termSessionId,
    55→    name: 'Codex CLI',
    56→    sessionKind: 'codex-cli',
    57→  });
    58→}
    59→
    60→class AgentOrchestrator extends EventEmitter {
    61→  constructor(projectRoot) {
    62→    super();
    63→    this.projectRoot = projectRoot;
    64→    this.workspaceManager = new WorkspaceManager(this.projectRoot);
    65→    this.runStore = new RunStore(path.join(this.projectRoot, '.clawcraft', 'runs'));
    66→    this.registry = new AgentRegistry();
    67→    this.messageBus = new MessageBus(path.join(this.projectRoot, '.clawcraft', 'shared'));
    68→    this.promptCompiler = new PromptCompiler(this.registry, this.messageBus, path.join(this.projectRoot, '.clawcraft', 'shared'));
    69→    this.adapters = new Map([
    70→      ['codex', new CodexAdapter()],
    71→      ['claude', new ClaudeAdapter()],
    72→      ['gemini', new GeminiAdapter()],
    73→    ]);
    74→    // Legacy compat: this.agents delegates to registry
    75→    this.agents = this.registry.agents;
    76→    this.activeRuns = new Map();
    77→    this.agentsFile = path.join(this.projectRoot, '.clawcraft', 'agents.json');
    78→    // Forward message bus events
    79→    this.messageBus.on('message', (msg) => {
    80→      this.emitEvent({ type: 'agent.message', message: msg });
    81→    });
    82→    // Restore agents from previous session, then clean orphans
    83→    this._restoreAgents();
    84→    this._pruneLegacySessionAgents();
    85→    this._ensurePrimarySessionAgent();
    86→    const knownIds = new Set(this.agents.keys());
    87→    this.workspaceManager.cleanupOrphanWorktrees(knownIds);
    88→  }
    89→
    90→  _restoreAgents() {
    91→    const fs = require('fs');
    92→    if (!fs.existsSync(this.agentsFile)) return;
    93→    try {
    94→      const data = JSON.parse(fs.readFileSync(this.agentsFile, 'utf8'));
    95→      for (const agent of data) {
    96→        const adapter = this.adapters.get(agent.engine || 'codex');
    97→        agent.available = adapter ? adapter.isAvailable() : false;
    98→        agent.workspace = this.workspaceManager.getWorkingContext(String(agent.id));
    99→        this.registry.register(agent);
   100→      }
   101→    } catch {}
   102→  }
   103→
   104→  _ensurePrimarySessionAgent() {
   105→    const primarySessionAgent = buildPrimarySessionAgent();
   106→    if (primarySessionAgent) {
   107→      this.createAgent(primarySessionAgent);
   108→    }
   109→  }
   110→
   111→  _pruneLegacySessionAgents() {
   112→    if (!this.agents.has('codex-session')) return;
   113→    this.agents.delete('codex-session');
   114→    try {
   115→      this.workspaceManager.removeWorktree('codex-session');
   116→    } catch {}
   117→    this._persistAgents();
   118→  }
   119→
   120→  _persistAgents() {
   121→    const fs = require('fs');
   122→    fs.writeFileSync(this.agentsFile, JSON.stringify(this.registry.toJSON(), null, 2));
   123→  }
   124→
   125→  listAgents() {
   126→    return this.registry.list();
   127→  }
   128→
   129→  getEngineStatuses() {
   130→    return [...this.adapters.values()].map((adapter) => adapter.describe());
   131→  }
   132→
   133→  getState() {
   134→    return {
   135→      agents: this.listAgents(),
   136→      runs: this.runStore.listRuns(),
   137→      engines: this.getEngineStatuses(),
   138→      liveMode: true,
   139→      parallelMode: 'git-worktree',
   140→      collaborationModes: ['solo', 'shared-brief', 'relay'],
   141→    };
   142→  }
   143→
   144→  // 4단계: Relay mode — chain agents sequentially, each gets previous output
   145→  async startRelay(payload) {
   146→    const { agentIds, prompt, taskTitle } = payload;
   147→    if (!agentIds || agentIds.length < 2) throw new Error('Relay에는 2개 이상의 에이전트가 필요합니다.');
   148→    const results = [];
   149→    let currentPrompt = prompt;
   150→    for (const agentId of agentIds) {
   151→      const agent = this.agents.get(String(agentId));
   152→      if (!agent) { results.push({ agentId, status: 'skipped', error: 'agent not found' }); continue; }
   153→      try {
   154→        const run = await this.startRun({ agentId: String(agentId), prompt: currentPrompt, taskTitle });
   155→        // Wait for run to complete
   156→        await new Promise((resolve, reject) => {
   157→          const handler = (event) => {
   158→            const eid = event.run?.id || event.runId;
   159→            if (eid !== run.id) return;
   160→            if (event.type === 'run.completed') { this.removeListener('event', handler); resolve(event); }
   161→            if (event.type === 'run.failed') { this.removeListener('event', handler); reject(new Error(event.errorText || 'failed')); }
