     2→// MESSAGE BUS — structured inter-agent communication
     3→// ═══════════════════════════════════════════════════════════════
     4→
     5→const fs = require('fs');
     6→const path = require('path');
     7→const { EventEmitter } = require('events');
     8→
     9→let msgCounter = 0;
    10→
    11→class MessageBus extends EventEmitter {
    12→  constructor(sharedDir) {
    13→    super();
    14→    this.sharedDir = sharedDir;
    15→    this.filePath = path.join(sharedDir, 'messages.ndjson');
    16→    this.memory = []; // in-memory queue for current session
    17→    fs.mkdirSync(sharedDir, { recursive: true });
    18→  }
    19→
    20→  // Send a structured message
    21→  send(msg) {
    22→    const entry = {
    23→      id: `msg_${Date.now()}_${++msgCounter}`,
    24→      from: msg.from || 'system',
    25→      fromName: msg.fromName || '',
    26→      to: msg.to || 'all',           // agentId | 'all' | 'team'
    27→      channel: msg.channel || 'radio', // radio | local | system
    28→      kind: msg.kind || 'chat',       // chat | task-update | request | report | error
    29→      text: msg.text || '',
    30→      relatedRunId: msg.relatedRunId || null,
    31→      at: new Date().toISOString(),
    32→    };
    33→    this.memory.push(entry);
    34→    if (this.memory.length > 200) this.memory = this.memory.slice(-200);
    35→    // Persist
    36→    fs.appendFileSync(this.filePath, JSON.stringify(entry) + '\n');
    37→    // Emit for real-time listeners
    38→    this.emit('message', entry);
    39→    return entry;
    40→  }
    41→
    42→  // Get recent messages (optionally filtered)
    43→  getRecent(opts = {}) {
    44→    const limit = opts.limit || 15;
    45→    const channel = opts.channel || null;
    46→    const forAgent = opts.forAgent || null;
    47→    let msgs = this.memory.length > 0 ? this.memory : this._loadFromDisk();
    48→    if (channel) msgs = msgs.filter(m => m.channel === channel);
    49→    if (forAgent) msgs = msgs.filter(m => m.to === 'all' || m.to === 'team' || m.to === forAgent || m.from === forAgent);
    50→    return msgs.slice(-limit);
    51→  }
    52→
    53→  // Get conversation visible to a specific agent
    54→  getConversationFor(agentId, limit = 10) {
    55→    return this.getRecent({ forAgent: agentId, limit });
    56→  }
    57→
    58→  // Clear (for testing)
    59→  clear() {
    60→    this.memory = [];
    61→    if (fs.existsSync(this.filePath)) fs.unlinkSync(this.filePath);
    62→  }
    63→
    64→  _loadFromDisk() {
    65→    if (!fs.existsSync(this.filePath)) return [];
    66→    const lines = fs.readFileSync(this.filePath, 'utf8').trim().split('\n').filter(Boolean);
    67→    return lines.map(l => { try { return JSON.parse(l); } catch { return null; } }).filter(Boolean);
    68→  }
    69→}
