    30→
    31→  // Clean up orphan worktrees left from previous sessions
    32→  cleanupOrphanWorktrees(knownAgentIds = new Set()) {
    33→    if (!fs.existsSync(this.worktreesDir)) return;
    34→    const entries = fs.readdirSync(this.worktreesDir, { withFileTypes: true });
    35→    for (const entry of entries) {
    36→      if (!entry.isDirectory() || !entry.name.startsWith('agent-')) continue;
    37→      const agentId = entry.name.replace('agent-', '');
    38→      if (!knownAgentIds.has(agentId)) {
    39→        console.log(`[WorkspaceManager] Cleaning orphan worktree: ${entry.name}`);
    40→        this.removeWorktree(agentId);
    41→      }
    42→    }
    43→  }
    44→
    45→  getSharedDir() {
    46→    return this.sharedDir;
    47→  }
    48→
    49→  createRunArtifacts(runId) {
    50→    const artifactsDir = path.join(this.runsDir, runId);
    51→    fs.mkdirSync(artifactsDir, { recursive: true });
    52→    return artifactsDir;
    53→  }
    54→
    55→  // ── Git worktree management ──
    56→
    57→  isGitRepo() {
    58→    try {
    59→      execSync('git rev-parse --is-inside-work-tree', { cwd: this.projectRoot, encoding: 'utf8', stdio: 'pipe' });
    60→      return true;
    61→    } catch { return false; }
    62→  }
    63→
    64→  createWorktree(agentId) {
    65→    if (!this.isGitRepo()) {
    66→      throw new Error('프로젝트가 Git 저장소가 아닙니다. 병렬 worktree를 생성할 수 없습니다.');
    67→    }
    68→    const branch = `agent/${agentId}`;
    69→    const worktreeDir = path.join(this.worktreesDir, `agent-${agentId}`);
    70→
    71→    // If worktree already exists, return it
    72→    if (fs.existsSync(worktreeDir)) {
    73→      return { workdir: worktreeDir, strategy: 'git-worktree', branch };
    74→    }
    75→
    76→    try {
    77→      // Create branch from current HEAD if it doesn't exist
    78→      try {
    79→        execSync(`git branch ${branch}`, { cwd: this.projectRoot, encoding: 'utf8', stdio: 'pipe' });
    80→      } catch {
    81→        // Branch already exists, that's fine
    82→      }
    83→      // Create worktree
    84→      execSync(`git worktree add "${worktreeDir}" ${branch}`, { cwd: this.projectRoot, encoding: 'utf8', stdio: 'pipe' });
    85→      return { workdir: worktreeDir, strategy: 'git-worktree', branch };
    86→    } catch (err) {
    87→      throw new Error(`Worktree 생성 실패 (agent ${agentId}): ${err.message}. 병렬 실행 불가.`);
    88→    }
    89→  }
    90→
    91→  removeWorktree(agentId) {
    92→    const worktreeDir = path.join(this.worktreesDir, `agent-${agentId}`);
    93→    const branch = `agent/${agentId}`;
    94→    if (!fs.existsSync(worktreeDir)) return;
    95→
    96→    try {
    97→      execSync(`git worktree remove "${worktreeDir}" --force`, { cwd: this.projectRoot, encoding: 'utf8', stdio: 'pipe' });
    98→    } catch (err) {
    99→      console.error(`[WorkspaceManager] Failed to remove worktree:`, err.message);
   100→      // Force cleanup directory
   101→      try { fs.rmSync(worktreeDir, { recursive: true, force: true }); } catch {}
   102→    }
   103→
   104→    // Clean up branch
   105→    try {
   106→      execSync(`git branch -D ${branch}`, { cwd: this.projectRoot, encoding: 'utf8', stdio: 'pipe' });
   107→    } catch {
   108→      // Branch might not exist or be checked out elsewhere
   109→    }
   110→  }
   111→
   112→  getWorkingContext(agentId) {
   113→    if (!agentId) {
   114→      return { workdir: this.projectRoot, strategy: 'in-place', branch: null };
   115→    }
   116→    const worktreeDir = path.join(this.worktreesDir, `agent-${agentId}`);
   117→    if (fs.existsSync(worktreeDir)) {
   118→      return { workdir: worktreeDir, strategy: 'git-worktree', branch: `agent/${agentId}` };
   119→    }
   120→    return this.createWorktree(agentId);
   121→  }
   122→
   123→  collectChangedFiles(worktreeDir, sinceMs) {
   124→    const baseDir = worktreeDir || this.projectRoot;
   125→    const changed = [];
   126→    const walk = (dir) => {
   127→      let entries;
   128→      try { entries = fs.readdirSync(dir, { withFileTypes: true }); } catch { return; }
   129→      for (const entry of entries) {
   130→        const fullPath = path.join(dir, entry.name);
   131→        if (entry.isDirectory()) {
   132→          if (SKIP_DIRS.has(entry.name)) continue;
   133→          walk(fullPath);
   134→          continue;
   135→        }
   136→        try {
   137→          const stat = fs.statSync(fullPath);
   138→          if (stat.mtimeMs >= sinceMs) {
   139→            changed.push(path.relative(baseDir, fullPath));
   140→          }
   141→        } catch {}
   142→      }
   143→    };
   144→    walk(baseDir);
   145→    return changed.sort();
   146→  }
   147→
   148→  // ── Shared context ──
   149→
   150→  getSharedBrief() {
   151→    const p = path.join(this.sharedDir, 'brief.md');
   152→    return fs.existsSync(p) ? fs.readFileSync(p, 'utf8') : '';
   153→  }
   154→
   155→  getDecisionLog() {
   156→    const p = path.join(this.sharedDir, 'decision-log.md');
   157→    return fs.existsSync(p) ? fs.readFileSync(p, 'utf8') : '';
   158→  }
   159→
   160→  getRecentMessages(limit = 10) {
   161→    const p = path.join(this.sharedDir, 'messages.ndjson');
   162→    if (!fs.existsSync(p)) return [];
   163→    const lines = fs.readFileSync(p, 'utf8').trim().split('\n').filter(Boolean);
   164→    return lines.slice(-limit).map(l => { try { return JSON.parse(l); } catch { return null; } }).filter(Boolean);
   165→  }
   166→
   167→  appendMessage(msg) {
   168→    const p = path.join(this.sharedDir, 'messages.ndjson');
   169→    const entry = { ...msg, at: new Date().toISOString() };
   170→    fs.appendFileSync(p, JSON.stringify(entry) + '\n');
   171→  }
   172→
   173→  buildSharedContext(currentAgentId, allAgents = []) {
   174→    const brief = this.getSharedBrief();
   175→    const decisions = this.getDecisionLog();
   176→    const recent = this.getRecentMessages(10);
   177→    let ctx = '';
   178→
   179→    // Team roster — who you are and who your teammates are
   180→    if (allAgents.length > 0) {
   181→      ctx += `## Your Identity\n`;
   182→      const me = allAgents.find(a => String(a.id) === String(currentAgentId));
   183→      if (me) {
   184→        ctx += `You are **${me.name}** (ID:${me.id}), engine: ${me.engine}, model: ${me.model}.\n\n`;
   185→      }
   186→      const teammates = allAgents.filter(a => String(a.id) !== String(currentAgentId));
   187→      if (teammates.length > 0) {
   188→        ctx += `## Team (your fellow SCV agents)\n`;
   189→        teammates.forEach(a => {
   190→          const statusText = a.status === 'running' ? '작업 중' : a.status === 'idle' ? '대기' : a.status;
   191→          ctx += `- **${a.name}** (ID:${a.id}) — ${a.engine}/${a.model} — ${statusText}${a.taskTitle && a.taskTitle !== 'Waiting' ? ` — "${a.taskTitle}"` : ''}\n`;
   192→        });
   193→        ctx += `\nYou can mention teammates by name. Your messages will be shared with them via the shared message log.\n\n`;
   194→      }
   195→    }
   196→
   197→    if (brief.trim().length > 20) ctx += `## Project Brief\n${brief}\n\n`;
   198→    if (decisions.trim().length > 20) ctx += `## Decision Log\n${decisions}\n\n`;
   199→
   200→    // Recent conversation / activity
   201→    if (recent.length > 0) {
   202→      ctx += `## Recent Team Conversation\n`;
   203→      recent.forEach(m => {
   204→        const sender = m.agentName || 'agent';
   205→        const text = m.text || m.summary || '';
   206→        if (text) ctx += `- **${sender}**: ${text.slice(0, 200)}\n`;
   207→      });
   208→      ctx += '\n';
   209→    }
   210→    return ctx;
   211→  }
   212→}
   213→
   214→module.exports = { WorkspaceManager };
   215→"}]},"parent_tool_use_id":"toolu_01DA9FVKLnarb8mZ4P6fupmm","session_id":"882ced72-4f4c-48a8-94aa-c54bd6e7bd3a","uuid":"206b7123-959f-479e-ba45-08ba0f9e0399"}

