{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_01672AC9GpLWNrE4GuWAWU79","type":"tool_result","content":"     1→// ═══════════════════════════════════════════════════════════════
     2→// AGENT REGISTRY — identity, team membership, presence
     3→// ═══════════════════════════════════════════════════════════════
     4→
     5→const DEFAULT_TEAM = 'terran-alpha';
     6→
     7→class AgentRegistry {
     8→  constructor() {
     9→    this.agents = new Map(); // id → AgentRecord
    10→  }
    11→
    12→  register(payload = {}) {
    13→    const id = String(payload.id || `${Date.now()}`);
    14→    const existing = this.agents.get(id);
    15→    if (existing) {
    16→      Object.assign(existing, this._patch(payload));
    17→      return existing;
    18→    }
    19→    const record = {
    20→      id,
    21→      sessionId: payload.sessionId || id,
    22→      name: payload.name || `Agent-${id}`,
    23→      engine: payload.engine || 'codex',
    24→      model: payload.model || 'gpt-5',
    25→      role: payload.role || 'builder',        // builder | reviewer | leader | assistant
    26→      teamId: payload.teamId || DEFAULT_TEAM,
    27→      relation: 'teammate',
    28→      locked: !!payload.locked,
    29→      sessionKind: payload.sessionKind || '',
    30→      taskTitle: payload.taskTitle || 'Waiting',
    31→      // Presence
    32→      status: 'idle',          // idle | running | failed | cancelled
    33→      currentRunId: null,
    34→      slot: payload.slot || null, // build slot position (set by renderer)
    35→      workspace: payload.workspace || null,
    36→    };
    37→    this.agents.set(id, record);
    38→    return record;
    39→  }
    40→
    41→  unregister(id) {
    42→    return this.agents.delete(String(id));
    43→  }
    44→
    45→  get(id) {
    46→    return this.agents.get(String(id));
    47→  }
    48→
    49→  list() {
    50→    return [...this.agents.values()];
    51→  }
    52→
    53→  listTeam(teamId) {
    54→    return this.list().filter(a => a.teamId === (teamId || DEFAULT_TEAM));
    55→  }
    56→
    57→  // Get structured world state from one agent's perspective
    58→  getPresenceFor(agentId) {
    59→    const me = this.get(agentId);
    60→    if (!me) return null;
    61→    const teammates = this.list().filter(a => a.id !== String(agentId) && a.teamId === me.teamId);
    62→    return {
    63→      self: {
    64→        id: me.id,
    65→        name: me.name,
    66→        engine: me.engine,
    67→        model: me.model,
    68→        role: me.role,
    69→        teamId: me.teamId,
    70→        status: me.status,
    71→        taskTitle: me.taskTitle,
    72→      },
    73→      teammates: teammates.map(a => ({
    74→        id: a.id,
    75→        name: a.name,
    76→        engine: a.engine,
    77→        model: a.model,
    78→        role: a.role,
    79→        status: a.status,
    80→        taskTitle: a.taskTitle,
    81→      })),
    82→    };
    83→  }
    84→
    85→  updatePresence(id, patch) {
    86→    const agent = this.get(id);
    87→    if (!agent) return null;
    88→    if (patch.status !== undefined) agent.status = patch.status;
    89→    if (patch.currentRunId !== undefined) agent.currentRunId = patch.currentRunId;
    90→    if (patch.taskTitle !== undefined) agent.taskTitle = patch.taskTitle;
    91→    if (patch.slot !== undefined) agent.slot = patch.slot;
    92→    if (patch.workspace !== undefined) agent.workspace = patch.workspace;
    93→    return agent;
    94→  }
    95→
    96→  toJSON() {
    97→    return this.list().map(a => ({
    98→      id: a.id, sessionId: a.sessionId, name: a.name,
    99→      engine: a.engine, model: a.model, role: a.role,
   100→      teamId: a.teamId, locked: a.locked,
   101→      sessionKind: a.sessionKind, taskTitle: a.taskTitle,
   102→    }));
   103→  }
   104→
   105→  _patch(p) {
   106→    const out = {};
   107→    if (p.name) out.name = p.name;
   108→    if (p.engine) out.engine = p.engine;
   109→    if (p.model) out.model = p.model;
   110→    if (p.role) out.role = p.role;
   111→    if (p.teamId) out.teamId = p.teamId;
   112→    if (p.locked !== undefined) out.locked = !!p.locked;
   113→    if (p.sessionKind) out.sessionKind = p.sessionKind;
   114→    if (p.taskTitle) out.taskTitle = p.taskTitle;
   115→    if (p.workspace) out.workspace = p.workspace;
   116→    return out;
   117→  }
   118→}
   119→
   120→module.exports = { AgentRegistry };
   121→"}]},"parent_tool_use_id":"toolu_01DA9FVKLnarb8mZ4P6fupmm","session_id":"882ced72-4f4c-48a8-94aa-c54bd6e7bd3a","uuid":"6c8cab0a-7e56-4547-9446-ba24f7cad6d7"}

